76	std::string String::ToModifiedUtf8() {
77	    if (IsCompressed()) {
78	        return std::string(reinterpret_cast<const char*>(GetValueCompressed()), GetLength());
79	    } else {
80	        uint64_t byte_count = GetUtfLength();
81	        std::string result(byte_count, static_cast<char>(0));
82	        ConvertUtf16ToModifiedUtf8(&result[0], byte_count, GetValue(), GetLength());
83	        return result;
84	    }
85	}
86	
87	int32_t String::GetUtfLength() {
88	    if (IsCompressed()) {
89	        return GetLength();
90	    } else {
91	        return CountUtf8Bytes(GetValue(), GetLength());
92	    }
93	}
94	
95	uint64_t String::SizeOf() {
96	    uint64_t size = SIZEOF(String);
97	    if (IsCompressed()) {
98	        size += sizeof(uint8_t) * GetLength();
99	    } else {
100	        size += sizeof(uint16_t) * GetLength();
101	    }
102	    return RoundUp(size, kObjectAlignment);
103	}
