67	namespace api {
68	class MemoryRef {
69	public:
70	    MemoryRef(uint64_t v) : vaddr(v), block(0) {}
71	    MemoryRef(const MemoryRef& ref) : vaddr(ref.vaddr), block(ref.block) {}
72	    MemoryRef(uint64_t v, LoadBlock* b) : vaddr(v), block(0) { checkCopyBlock(b); }
73	    MemoryRef(uint64_t v, MemoryRef& ref) : vaddr(v), block(0) { copyRef(ref); }
74	    MemoryRef(uint64_t v, MemoryRef* ref) : vaddr(v), block(0) { copyRef(ref); }
75	
76	    inline void checkCopyBlock(LoadBlock* b) { if (b && b->virtualContains(vaddr)) block = b; }
77	    inline void copyRef(MemoryRef& ref) { checkCopyBlock(ref.block); }
78	    inline void copyRef(MemoryRef* ref) { checkCopyBlock(ref->block); }
79	
80	    inline bool operator==(uint64_t v) { return vaddr == v; }
81	    inline bool operator!=(uint64_t v) { return vaddr != v; }
82	    inline bool operator==(MemoryRef& ref) const { return Ptr() == ref.Ptr(); }
83	    inline bool operator!=(MemoryRef& ref) const { return Ptr() != ref.Ptr(); }
84	    inline bool operator<(MemoryRef& ref) const { return Ptr() < ref.Ptr(); }
85	    inline bool operator>(MemoryRef& ref) const { return Ptr() > ref.Ptr(); }
86	    inline bool operator<=(MemoryRef& ref) const { return Ptr() <= ref.Ptr(); }
87	    inline bool operator>=(MemoryRef& ref) const { return Ptr() >= ref.Ptr(); }
88	
89	    inline uint64_t Ptr() { return vaddr; }
90	    inline uint64_t Ptr() const { return vaddr; }
91	    inline uint64_t Real() {
92	        Prepare(true);
93	
94	        if (!block || !block->isValid())
95	            throw InvalidAddressException(vaddr);
96	
97	        return block->begin() + ((vaddr & block->VabitsMask()) - block->vaddr());
98	    }
99	    inline LoadBlock* Block() { return block; }
100	    inline uint64_t PointMask() { return block->PointMask(); }
101	    inline bool IsReady() { return block != nullptr; }
102	    inline void Prepare(bool check) {
103	        if (block || !vaddr) return;
104	        block = Bridge::FindLoadBlock(vaddr, check);
105	    }
106	    /*
107	     * Must check quick cache is same.
108	     */
109	    inline void MovePtr(int64_t length) {
110	        Prepare(true);
111	        if (block && block->virtualContains(vaddr + length)) {
112	            vaddr = vaddr + length;
113	        } else {
114	            vaddr = vaddr + length;
115	            block = nullptr;
116	        }
117	    }
118	    inline bool IsValid() {
119	        Prepare(false);
120	        if (block && block->isValid())
121	            return true;
122	        return false;
123	    }
124	    inline uint64_t valueOf() { return valueOf(0); }
125	    inline uint64_t valueOf(uint64_t offset) {
126	        return *reinterpret_cast<uint64_t *>(Real() + offset) & PointMask();
127	    }
128	    inline uint64_t value64Of() { return value64Of(0); }
129	    inline uint64_t value64Of(uint64_t offset) {
130	        return *reinterpret_cast<uint64_t *>(Real() + offset);
131	    }
132	    inline uint32_t value32Of() { return value32Of(0); }
133	    inline uint32_t value32Of(uint64_t offset) {
134	        return *reinterpret_cast<uint32_t *>(Real() + offset);
135	    }
136	    inline uint32_t value16Of() { return value16Of(0); }
137	    inline uint32_t value16Of(uint64_t offset) {
138	        return *reinterpret_cast<uint16_t *>(Real() + offset);
139	    }
140	    inline uint32_t value8Of() { return value8Of(0); }
141	    inline uint32_t value8Of(uint64_t offset) {
142	        return *reinterpret_cast<uint8_t *>(Real() + offset);
143	    }
144	private:
145	    uint64_t vaddr;
146	    LoadBlock* block;
147	};
